import React from "react";
import { BrowserRouter, Routes, Route, Link, Outlet } from "react-router-dom";

function Home() {
  return <h1>Home Page!</h1>;
}
function Menu() {
  return (
    <>
      <h2>Menu page</h2>
      <nav>
        <link to="/menu/fast">FastFood</link>
        <link to="/menu/guj">Gujarati</link>
      </nav>
      <Outlet />
    </>
  );
}
function FastFood() {
  return (
    <>
      <h1>Fast food Menu</h1>
      <ul>
        <li>Burger</li>
        <li>Pizzaa</li>
        <li>FrenchFries</li>
        <li>NAchozz</li>
      </ul>
    </>
  );
}
function Gujarati() {
  return (
    <>
      <h2>Gujarati Thali</h2>
      <ul>
        <li>Kaju lasan</li>
        <li>Kaju Paneer</li>
        <li>Sev Tameta</li>
      </ul>
    </>
  );
}
function Payment() {
  return <h2>Payment Details Page </h2>;
}
function Navigation() {
  return (
    <>
      <BrowserRouter>
        <nav>
          <Link to="/">Home</Link> <Link to="/menu">Menu</Link>{" "}
          <Link to="/payment">Payment</Link>{" "}
        </nav>
        <Routes>
          <Route path="/" element={<Home />} />
          <Route path="/menu" element={<Menu />} />
          <Route path="/fast" element={<FastFood />} />
          <Route path="/guj" element={<Gujarati />} />
          <Route path="/payment" element={<Payment />} />
        </Routes>
      </BrowserRouter>
    </>
  );
}
export default Navigation;
